curl --location 'wss://piconnect.flattrade.in/PiConnectWSAPI/' 
--data '{
    "t": "t",
    "k": "NSE|22#BSE|508123#NSE|10#BSE|2879"
}'

# Unsubscribe (verbatim from page 71 — the doc places the ack value 'uk', not 'u', in this request body):
curl --location 'wss://piconnect.flattrade.in/PiConnectWSAPI/' 
--data '{
    "t": "uk",
    "k": "NSE|22#BSE|508123#NSE|10#BSE|2879"
}'

# Subscribe Depth:
curl --location 'wss://piconnect.flattrade.in/PiConnectWSAPI/' 
--data '{
    "t": "d",  
    "k": "NSE|22#BSE|508123#NSE|10#BSE|2879"
}'

# Unsubscribe Depth:
curl --location 'wss://piconnect.flattrade.in/PiConnectWSAPI/' 
--data '{
    "t": "ud",  
    "k": "NSE|22#BSE|508123#NSE|10#BSE|2879"
}'

